#include <stdio.h>
#include <string.h>

int main(){
    int T;
    if(scanf("%d",&T)!=1)return 0;
    while(T--){
        char S1[1005];
        char S2[1005];
        scanf("%s",S1);
        scanf("%s",S2);
        if(strstr(S1,S2)!=NULL)printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

