int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if(!(cin>>T))return 0;
    while(T--){
        string S1,S2;
        cin>>S1>>S2;
        cout<<(S1.find(S2)!=string::npos?"YES":"NO")<<'\n';
    }
    return 0;
